 64â†’// parseTranscriptFromLine reads and parses a transcript file starting from a specific line.
 65â†’// Uses bufio.Reader to handle arbitrarily long lines.
 66â†’// Returns:
 67â†’//   - lines: parsed transcript lines from startLine onwards (malformed lines skipped)
 68â†’//   - totalLines: total number of lines in the file (including malformed ones)
 69â†’//   - error: any error encountered during reading
 70â†’//
 71â†’// The startLine parameter is 0-indexed (startLine=0 reads from the beginning).
 72â†’// This is useful for incremental parsing when you've already processed some lines.
 73â†’func parseTranscriptFromLine(path string, startLine int) ([]transcriptLine, int, error) {
 74â†’	file, err := os.Open(path) //nolint:gosec // path is a controlled transcript file path
 75â†’	if err != nil {
 76â†’		return nil, 0, fmt.Errorf("failed to open transcript: %w", err)
 77â†’	}
 78â†’	defer func() { _ = file.Close() }()
 79â†’
 80â†’	var lines []transcriptLine
 81â†’	reader := bufio.NewReader(file)
 82â†’
 83â†’	totalLines := 0
 84â†’	for {
