114â†’
115â†’// parseTranscriptFromBytes parses transcript content from a byte slice.
116â†’// Uses bufio.Reader to handle arbitrarily long lines.
117â†’func parseTranscriptFromBytes(content []byte) ([]transcriptLine, error) {
118â†’	lines, err := transcript.ParseFromBytes(content)
119â†’	if err != nil {
120â†’		return nil, fmt.Errorf("failed to parse transcript: %w", err)
121â†’	}
