125â†’// PromptResponsePair represents a user prompt and the assistant's responses.
126â†’// Used for extracting all interactions from a transcript.
127â†’type PromptResponsePair struct {
128â†’	Prompt    string
129â†’	Responses []string // Multiple responses can occur between tool calls
130â†’	Files     []string
131â†’}
132â†’
133â†’// ExtractAllPromptResponses extracts all user prompt and assistant response pairs from a transcript.
134â†’// Returns pairs in chronological order (oldest first).
135â†’// Each pair contains the user's prompt, assistant's text response, and files modified.
136â†’func ExtractAllPromptResponses(transcript []transcriptLine) []PromptResponsePair {
137â†’	var pairs []PromptResponsePair
138â†’
139â†’	// Find all user prompts (messages with string content, not tool results)
140â†’	var userIndices []int
141â†’	for i, line := range transcript {
142â†’		if line.Type == transcriptTypeUser {
143â†’			var msg userMessage
144â†’			if err := json.Unmarshal(line.Message, &msg); err != nil {
145â†’				continue
146â†’			}
147â†’			// Only count messages with string content (real user prompts)
148â†’			if _, ok := msg.Content.(string); ok {
149â†’				userIndices = append(userIndices, i)
150â†’			} else if arr, ok := msg.Content.([]interface{}); ok {
151â†’				// Check if array has text blocks (also a real user prompt)
152â†’				for _, item := range arr {
153â†’					if m, ok := item.(map[string]interface{}); ok {
154â†’						if m["type"] == contentTypeText {
155â†’							userIndices = append(userIndices, i)
156â†’							break
157â†’						}
158â†’					}
159â†’				}
160â†’			}
161â†’		}
162â†’	}
163â†’
164â†’	// For each user prompt, extract the prompt text, following assistant response, and files
165â†’	for idx, userIdx := range userIndices {
166â†’		// Determine the range for this prompt's conversation
167â†’		endIdx := len(transcript)
168â†’		if idx < len(userIndices)-1 {
169â†’			endIdx = userIndices[idx+1]
170â†’		}
171â†’
172â†’		// Extract prompt text
173â†’		prompt := extractUserPromptAt(transcript, userIdx)
174â†’		if prompt == "" {
175â†’			continue
176â†’		}
177â†’
178â†’		// Extract assistant responses and files from this range
179â†’		slice := transcript[userIdx:endIdx]
180â†’		responses := extractAssistantResponses(slice)
181â†’		files := extractModifiedFiles(slice)
182â†’
183â†’		pairs = append(pairs, PromptResponsePair{
184â†’			Prompt:    prompt,
185â†’			Responses: responses,
186â†’			Files:     files,
187â†’		})
188â†’	}
189â†’
