203â†’// extractAssistantResponses collects all assistant text blocks from the given transcript slice.
204â†’// A single prompt can trigger multiple assistant responses interspersed with tool calls.
205â†’func extractAssistantResponses(transcript []transcriptLine) []string {
206â†’	var texts []string
207â†’	for _, line := range transcript {
208â†’		if line.Type == transcriptTypeAssistant {
209â†’			var msg assistantMessage
210â†’			if err := json.Unmarshal(line.Message, &msg); err != nil {
211â†’				continue
212â†’			}
213â†’
214â†’			for _, block := range msg.Content {
