335â†’	var files []string
336â†’
337â†’	for _, line := range transcript {
338â†’		if line.Type == transcriptTypeAssistant {
339â†’			var msg assistantMessage
340â†’			if err := json.Unmarshal(line.Message, &msg); err != nil {
341â†’				continue
342â†’			}
343â†’
344â†’			for _, block := range msg.Content {
345â†’				if block.Type == contentTypeToolUse {
346â†’					isModifyTool := false
347â†’					for _, name := range claudecode.FileModificationTools {
348â†’						if block.Name == name {
349â†’							isModifyTool = true
350â†’							break
351â†’						}
352â†’					}
353â†’
354â†’					if isModifyTool {
355â†’						var input toolInput
356â†’						if err := json.Unmarshal(block.Input, &input); err != nil {
357â†’							continue
358â†’						}
359â†’
360â†’						file := input.FilePath
361â†’						if file == "" {
362â†’							file = input.NotebookPath
363â†’						}
364â†’
365â†’						if file != "" && !fileSet[file] {
366â†’							fileSet[file] = true
367â†’							files = append(files, file)
368â†’						}
369â†’					}
370â†’				}
371â†’			}
372â†’		}
373â†’	}
374â†’
375â†’	return files
376â†’}
377â†’
378â†’// extractKeyActions extracts key actions from the transcript for context file
379â†’func extractKeyActions(transcript []transcriptLine, maxActions int) []string {
380â†’	var keyActions []string
381â†’
382â†’	for _, line := range transcript {
383â†’		if line.Type == transcriptTypeAssistant {
384â†’			var msg assistantMessage
385â†’			if err := json.Unmarshal(line.Message, &msg); err != nil {
386â†’				continue
387â†’			}
388â†’
389â†’			for _, block := range msg.Content {
390â†’				if block.Type == contentTypeToolUse {
391â†’					var input toolInput
392â†’					_ = json.Unmarshal(block.Input, &input) //nolint:errcheck // Best-effort parsing for display purposes
393â†’
394â†’					detail := input.Description
395â†’					if detail == "" {
396â†’						detail = input.Command
397â†’					}
398â†’					if detail == "" {
399â†’						detail = input.FilePath
400â†’					}
401â†’					if detail == "" {
402â†’						detail = input.Pattern
403â†’					}
404â†’
405â†’					action := "- **" + block.Name + "**: " + detail
