 43â†’		// Handle empty line or EOF without content
 44â†’		if len(lineBytes) == 0 {
 45â†’			if err == io.EOF {
 46â†’				break
 47â†’			}
 48â†’			continue
 49â†’		}
 50â†’
 51â†’		var line transcriptLine
 52â†’		if err := json.Unmarshal(lineBytes, &line); err == nil {
 53â†’			lines = append(lines, line)
 54â†’		}
 55â†’
 56â†’		if err == io.EOF {
 57â†’			break
 58â†’		}
 59â†’	}
 60â†’
 61â†’	return lines, nil
 62â†’}
 63â†’
 64â†’// parseTranscriptFromLine reads and parses a transcript file starting from a specific line.
 65â†’// Uses bufio.Reader to handle arbitrarily long lines.
 66â†’// Returns:
 67â†’//   - lines: parsed transcript lines from startLine onwards (malformed lines skipped)
 68â†’//   - totalLines: total number of lines in the file (including malformed ones)
 69â†’//   - error: any error encountered during reading
 70â†’//
 71â†’// The startLine parameter is 0-indexed (startLine=0 reads from the beginning).
 72â†’// This is useful for incremental parsing when you've already processed some lines.
 73â†’func parseTranscriptFromLine(path string, startLine int) ([]transcriptLine, int, error) {
 74â†’	file, err := os.Open(path) //nolint:gosec // path is a controlled transcript file path
 75â†’	if err != nil {
 76â†’		return nil, 0, fmt.Errorf("failed to open transcript: %w", err)
 77â†’	}
 78â†’	defer func() { _ = file.Close() }()
 79â†’
 80â†’	var lines []transcriptLine
 81â†’	reader := bufio.NewReader(file)
 82â†’
 83â†’	totalLines := 0
 84â†’	for {
 85â†’		lineBytes, err := reader.ReadBytes('\n')
 86â†’		if err != nil && err != io.EOF {
 87â†’			return nil, 0, fmt.Errorf("failed to read transcript: %w", err)
 88â†’		}
 89â†’
 90â†’		// Handle empty line or EOF without content
 91â†’		if len(lineBytes) == 0 {
 92â†’			if err == io.EOF {
 93â†’				break
 94â†’			}
 95â†’			continue
 96â†’		}
 97â†’
 98â†’		// Count all lines for totalLines, but only parse after startLine
 99â†’		if totalLines >= startLine {
100â†’			var line transcriptLine
101â†’			if err := json.Unmarshal(lineBytes, &line); err == nil {
102â†’				lines = append(lines, line)
103â†’			}
104â†’		}
105â†’		totalLines++
106â†’
107â†’		if err == io.EOF {
108â†’			break
109â†’		}
110â†’	}
111â†’
112â†’	return lines, totalLines, nil
113â†’}
114â†’
115â†’// parseTranscriptFromBytes parses transcript content from a byte slice.
116â†’// Uses bufio.Reader to handle arbitrarily long lines.
117â†’func parseTranscriptFromBytes(content []byte) ([]transcriptLine, error) {
118â†’	lines, err := transcript.ParseFromBytes(content)
119â†’	if err != nil {
120â†’		return nil, fmt.Errorf("failed to parse transcript: %w", err)
121â†’	}
122â†’	return lines, nil
123â†’}
124â†’
125â†’// PromptResponsePair represents a user prompt and the assistant's responses.
126â†’// Used for extracting all interactions from a transcript.
127â†’type PromptResponsePair struct {
128â†’	Prompt    string
129â†’	Responses []string // Multiple responses can occur between tool calls
130â†’	Files     []string
131â†’}
132â†’
133â†’// ExtractAllPromptResponses extracts all user prompt and assistant response pairs from a transcript.
134â†’// Returns pairs in chronological order (oldest first).
135â†’// Each pair contains the user's prompt, assistant's text response, and files modified.
136â†’func ExtractAllPromptResponses(transcript []transcriptLine) []PromptResponsePair {
137â†’	var pairs []PromptResponsePair
138â†’
139â†’	// Find all user prompts (messages with string content, not tool results)
140â†’	var userIndices []int
141â†’	for i, line := range transcript {
142â†’		if line.Type == transcriptTypeUser {
143â†’			var msg userMessage
144â†’			if err := json.Unmarshal(line.Message, &msg); err != nil {
145â†’				continue
146â†’			}
147â†’			// Only count messages with string content (real user prompts)
148â†’			if _, ok := msg.Content.(string); ok {
149â†’				userIndices = append(userIndices, i)
150â†’			} else if arr, ok := msg.Content.([]interface{}); ok {
151â†’				// Check if array has text blocks (also a real user prompt)
152â†’				for _, item := range arr {
153â†’					if m, ok := item.(map[string]interface{}); ok {
154â†’						if m["type"] == contentTypeText {
155â†’							userIndices = append(userIndices, i)
156â†’							break
157â†’						}
158â†’					}
159â†’				}
160â†’			}
161â†’		}
162â†’	}
163â†’
164â†’	// For each user prompt, extract the prompt text, following assistant response, and files
165â†’	for idx, userIdx := range userIndices {
166â†’		// Determine the range for this prompt's conversation
167â†’		endIdx := len(transcript)
168â†’		if idx < len(userIndices)-1 {
169â†’			endIdx = userIndices[idx+1]
170â†’		}
171â†’
172â†’		// Extract prompt text
173â†’		prompt := extractUserPromptAt(transcript, userIdx)
174â†’		if prompt == "" {
175â†’			continue
176â†’		}
177â†’
178â†’		// Extract assistant responses and files from this range
179â†’		slice := transcript[userIdx:endIdx]
180â†’		responses := extractAssistantResponses(slice)
181â†’		files := extractModifiedFiles(slice)
182â†’
183â†’		pairs = append(pairs, PromptResponsePair{
184â†’			Prompt:    prompt,
185â†’			Responses: responses,
186â†’			Files:     files,
187â†’		})
188â†’	}
189â†’
190â†’	return pairs
191â†’}
192â†’
193â†’// extractUserPromptAt extracts the user prompt at the given index.
194â†’// IDE-injected context tags (like <ide_opened_file>) are stripped from the result.
195â†’func extractUserPromptAt(lines []transcriptLine, idx int) string {
196â†’	if idx >= len(lines) || lines[idx].Type != transcriptTypeUser {
197â†’		return ""
198â†’	}
199â†’
200â†’	return transcript.ExtractUserContent(lines[idx].Message)
201â†’}
202â†’
203â†’// extractAssistantResponses collects all assistant text blocks from the given transcript slice.
204â†’// A single prompt can trigger multiple assistant responses interspersed with tool calls.
205â†’func extractAssistantResponses(transcript []transcriptLine) []string {
206â†’	var texts []string
207â†’	for _, line := range transcript {
208â†’		if line.Type == transcriptTypeAssistant {
209â†’			var msg assistantMessage
210â†’			if err := json.Unmarshal(line.Message, &msg); err != nil {
211â†’				continue
212â†’			}
213â†’
214â†’			for _, block := range msg.Content {
215â†’				if block.Type == contentTypeText && block.Text != "" {
216â†’					texts = append(texts, block.Text)
217â†’				}
218â†’			}
219â†’		}
220â†’	}
221â†’	return texts
222â†’}
223â†’
224â†’// extractUserPrompts extracts all user messages from the transcript in order.
225â†’// Only considers messages with string content (not tool results).
226â†’// IDE-injected context tags (like <ide_opened_file>) are stripped from the results.
227â†’func extractUserPrompts(transcript []transcriptLine) []string {
228â†’	var prompts []string
229â†’	for i := range transcript {
230â†’		if transcript[i].Type != transcriptTypeUser {
231â†’			continue
232â†’		}
233â†’		var msg userMessage
234â†’		if err := json.Unmarshal(transcript[i].Message, &msg); err != nil {
235â†’			continue
236â†’		}
237â†’
238â†’		// Handle string content
239â†’		if str, ok := msg.Content.(string); ok {
240â†’			prompts = append(prompts, textutil.StripIDEContextTags(str))
241â†’			continue
242â†’		}
243â†’
244â†’		// Handle array content (only if it contains text blocks)
245â†’		if arr, ok := msg.Content.([]interface{}); ok {
246â†’			var texts []string
247â†’			for _, item := range arr {
248â†’				if m, ok := item.(map[string]interface{}); ok {
249â†’					if m["type"] == contentTypeText {
250â†’						if text, ok := m["text"].(string); ok {
251â†’							texts = append(texts, text)
252â†’						}
253â†’					}
254â†’				}
255â†’			}
256â†’			if len(texts) > 0 {
257â†’				prompts = append(prompts, textutil.StripIDEContextTags(strings.Join(texts, "\n\n")))
258â†’			}
259â†’		}
260â†’	}
261â†’	return prompts
262â†’}
263â†’
264â†’// extractLastUserPrompt extracts the last user message from the transcript.
265â†’// Only considers messages with string content (not tool results).
266â†’// IDE-injected context tags (like <ide_opened_file>) are stripped from the result.
267â†’func extractLastUserPrompt(transcript []transcriptLine) string {
268â†’	prompts := extractUserPrompts(transcript)
269â†’	if len(prompts) == 0 {
270â†’		return ""
271â†’	}
272â†’	return prompts[len(prompts)-1]
273â†’}
274â†’
275â†’// extractLastAssistantMessage extracts the last text message from the assistant
276â†’func extractLastAssistantMessage(transcript []transcriptLine) string {
277â†’	for i := len(transcript) - 1; i >= 0; i-- {
278â†’		if transcript[i].Type == transcriptTypeAssistant {
279â†’			var msg assistantMessage
280â†’			if err := json.Unmarshal(transcript[i].Message, &msg); err != nil {
281â†’				continue
282â†’			}
283â†’
284â†’			for _, block := range msg.Content {
285â†’				if block.Type == contentTypeText && block.Text != "" {
286â†’					return block.Text
287â†’				}
288â†’			}
289â†’		}
290â†’	}
291â†’	return ""
292â†’}
293â†’
294â†’// findLastUserUUID finds the UUID of the last user message (that has string content)
295â†’func findLastUserUUID(transcript []transcriptLine) string {
296â†’	for i := len(transcript) - 1; i >= 0; i-- {
297â†’		if transcript[i].Type == transcriptTypeUser {
298â†’			var msg userMessage
299â†’			if err := json.Unmarshal(transcript[i].Message, &msg); err != nil {
300â†’				continue
301â†’			}
302â†’			// Only count messages with string content (not tool results)
303â†’			if _, ok := msg.Content.(string); ok {
304â†’				return transcript[i].UUID
305â†’			}
306â†’		}
307â†’	}
308â†’	return ""
309â†’}
310â†’
311â†’// filterTranscriptAfterUUID returns transcript lines after the given UUID
312â†’func filterTranscriptAfterUUID(transcript []transcriptLine, uuid string) []transcriptLine {
313â†’	if uuid == "" {
314â†’		return transcript
315â†’	}
316â†’
317â†’	foundIndex := -1
318â†’	for i, line := range transcript {
319â†’		if line.UUID == uuid {
320â†’			foundIndex = i
321â†’			break
322â†’		}
323â†’	}
324â†’
325â†’	if foundIndex == -1 || foundIndex == len(transcript)-1 {
326â†’		return transcript
327â†’	}
328â†’
329â†’	return transcript[foundIndex+1:]
330â†’}
331â†’
332â†’// extractModifiedFiles extracts the list of files modified by tool calls
333â†’func extractModifiedFiles(transcript []transcriptLine) []string {
334â†’	fileSet := make(map[string]bool)
335â†’	var files []string
336â†’
337â†’	for _, line := range transcript {
338â†’		if line.Type == transcriptTypeAssistant {
339â†’			var msg assistantMessage
340â†’			if err := json.Unmarshal(line.Message, &msg); err != nil {
341â†’				continue
342â†’			}
343â†’
344â†’			for _, block := range msg.Content {
345â†’				if block.Type == contentTypeToolUse {
346â†’					isModifyTool := false
347â†’					for _, name := range claudecode.FileModificationTools {
348â†’						if block.Name == name {
349â†’							isModifyTool = true
350â†’							break
351â†’						}
352â†’					}
353â†’
354â†’					if isModifyTool {
355â†’						var input toolInput
356â†’						if err := json.Unmarshal(block.Input, &input); err != nil {
357â†’							continue
358â†’						}
359â†’
360â†’						file := input.FilePath
361â†’						if file == "" {
362â†’							file = input.NotebookPath
363â†’						}
364â†’
365â†’						if file != "" && !fileSet[file] {
366â†’							fileSet[file] = true
367â†’							files = append(files, file)
368â†’						}
369â†’					}
370â†’				}
371â†’			}
372â†’		}
373â†’	}
374â†’
375â†’	return files
376â†’}
