378â†’// extractKeyActions extracts key actions from the transcript for context file
379â†’func extractKeyActions(transcript []transcriptLine, maxActions int) []string {
380â†’	var keyActions []string
381â†’
382â†’	for _, line := range transcript {
383â†’		if line.Type == transcriptTypeAssistant {
384â†’			var msg assistantMessage
385â†’			if err := json.Unmarshal(line.Message, &msg); err != nil {
386â†’				continue
387â†’			}
388â†’
389â†’			for _, block := range msg.Content {
390â†’				if block.Type == contentTypeToolUse {
391â†’					var input toolInput
392â†’					_ = json.Unmarshal(block.Input, &input) //nolint:errcheck // Best-effort parsing for display purposes
393â†’
394â†’					detail := input.Description
395â†’					if detail == "" {
396â†’						detail = input.Command
397â†’					}
398â†’					if detail == "" {
399â†’						detail = input.FilePath
400â†’					}
401â†’					if detail == "" {
402â†’						detail = input.Pattern
403â†’					}
404â†’
405â†’					action := "- **" + block.Name + "**: " + detail
406â†’					keyActions = append(keyActions, action)
407â†’					if len(keyActions) >= maxActions {
408â†’						return keyActions
409â†’					}
410â†’				}
411â†’			}
412â†’		}
413â†’	}
414â†’
415â†’	return keyActions
416â†’}
