418â†’// AgentTranscriptPath returns the path to a subagent's transcript file.
419â†’// Subagent transcripts are stored as agent-{agentId}.jsonl in the same directory
420â†’// as the main transcript.
421â†’func AgentTranscriptPath(transcriptDir, agentID string) string {
422â†’	return filepath.Join(transcriptDir, fmt.Sprintf("agent-%s.jsonl", agentID))
423â†’}
