425â†’// toolResultBlock represents a tool_result in a user message
426â†’type toolResultBlock struct {
427â†’	Type      string `json:"type"`
428â†’	ToolUseID string `json:"tool_use_id"`
429â†’}
430â†’
431â†’// userMessageWithToolResults represents a user message that may contain tool results
432â†’type userMessageWithToolResults struct {
