436â†’// FindCheckpointUUID finds the UUID of the message containing the tool_result
437â†’// for the given tool_use_id. This is used to find the checkpoint point for
438â†’// transcript truncation when rewinding to a task.
439â†’// Returns the UUID and true if found, empty string and false otherwise.
440â†’func FindCheckpointUUID(transcript []transcriptLine, toolUseID string) (string, bool) {
441â†’	for _, line := range transcript {
442â†’		if line.Type != transcriptTypeUser {
443â†’			continue
444â†’		}
445â†’
446â†’		var msg userMessageWithToolResults
447â†’		if err := json.Unmarshal(line.Message, &msg); err != nil {
448â†’			continue
449â†’		}
450â†’
451â†’		for _, block := range msg.Content {
452â†’			if block.Type == "tool_result" && block.ToolUseID == toolUseID {
453â†’				return line.UUID, true
454â†’			}
455â†’		}
456â†’	}
457â†’	return "", false
