460â†’// TruncateTranscriptAtUUID returns transcript lines up to and including the
461â†’// line with the given UUID. If the UUID is not found or is empty, returns
462â†’// the entire transcript.
463â†’//
464â†’//nolint:revive // Exported for testing purposes
465â†’func TruncateTranscriptAtUUID(transcript []transcriptLine, uuid string) []transcriptLine {
466â†’	if uuid == "" {
467â†’		return transcript
468â†’	}
469â†’
470â†’	for i, line := range transcript {
471â†’		if line.UUID == uuid {
472â†’			return transcript[:i+1]
473â†’		}
474â†’	}
