480â†’// writeTranscript writes transcript lines to a file in JSONL format.
481â†’func writeTranscript(path string, transcript []transcriptLine) error {
482â†’	file, err := os.Create(path) //nolint:gosec // Writing to controlled git metadata path
483â†’	if err != nil {
484â†’		return fmt.Errorf("failed to create file: %w", err)
485â†’	}
486â†’	defer func() { _ = file.Close() }()
487â†’
488â†’	for _, line := range transcript {
489â†’		data, err := json.Marshal(line)
490â†’		if err != nil {
491â†’			return fmt.Errorf("failed to marshal line: %w", err)
492â†’		}
493â†’		if _, err := file.Write(data); err != nil {
