510â†’// GetTranscriptPosition reads a transcript file and returns the last UUID and line count.
511â†’// Returns empty position if file doesn't exist or is empty.
512â†’// Only considers UUIDs from actual messages (user/assistant), not summary rows which use leafUuid.
513â†’func GetTranscriptPosition(path string) (TranscriptPosition, error) {
514â†’	if path == "" {
515â†’		return TranscriptPosition{}, nil
516â†’	}
517â†’
518â†’	file, err := os.Open(path) //nolint:gosec // Reading from controlled transcript path
519â†’	if err != nil {
520â†’		if os.IsNotExist(err) {
521â†’			return TranscriptPosition{}, nil
522â†’		}
523â†’		return TranscriptPosition{}, fmt.Errorf("failed to open transcript: %w", err)
524â†’	}
525â†’	defer func() { _ = file.Close() }()
526â†’
527â†’	var pos TranscriptPosition
528â†’	reader := bufio.NewReader(file)
529â†’
530â†’	for {
531â†’		lineBytes, err := reader.ReadBytes('\n')
532â†’		if err != nil && err != io.EOF {
533â†’			return TranscriptPosition{}, fmt.Errorf("failed to read transcript: %w", err)
534â†’		}
535â†’
536â†’		if len(lineBytes) == 0 {
537â†’			if err == io.EOF {
538â†’				break
539â†’			}
540â†’			continue
541â†’		}
542â†’
543â†’		pos.LineCount++
544â†’
545â†’		// Parse line to extract UUID (only from user/assistant messages, not summaries)
546â†’		var line transcriptLine
547â†’		if err := json.Unmarshal(lineBytes, &line); err == nil {
548â†’			if line.UUID != "" {
549â†’				pos.LastUUID = line.UUID
550â†’			}
551â†’		}
552â†’
553â†’		if err == io.EOF {
554â†’			break
555â†’		}
556â†’	}
557â†’
558â†’	return pos, nil
559â†’}
