	if _, err := os.Stat(transcriptPath); err != nil {
		if os.IsNotExist(err) {
			return "", nil // Not found, but not an error
		}
		return "", fmt.Errorf("failed to stat transcript: %w", err)
	}

	return transcriptPath, nil
}

