	}

	// Restore logs
	sessions, err := restorer.RestoreLogsOnly(point, true) // force=true for explicit rewind
	if err != nil {
		logging.Error(ctx, "logs-only restore failed",
			slog.String("checkpoint_id", point.ID),
			slog.String("error", err.Error()),
