387â†’// CalculateTotalTokenUsage calculates token usage for a turn, including subagents.
388â†’// It parses the main transcript from startLine, extracts spawned agent IDs,
389â†’// and calculates their token usage from transcripts in subagentsDir.
390â†’func CalculateTotalTokenUsage(transcriptPath string, startLine int, subagentsDir string) (*agent.TokenUsage, error) {
