410â†’		for agentID := range agentIDs {
411â†’			agentPath := filepath.Join(subagentsDir, fmt.Sprintf("agent-%s.jsonl", agentID))
412â†’			agentUsage, err := CalculateTokenUsageFromFile(agentPath, 0)
413â†’			if err != nil {
