415â†’				continue
416â†’			}
417â†’			subagentUsage.InputTokens += agentUsage.InputTokens
418â†’			subagentUsage.CacheCreationTokens += agentUsage.CacheCreationTokens
419â†’			subagentUsage.CacheReadTokens += agentUsage.CacheReadTokens
420â†’			subagentUsage.OutputTokens += agentUsage.OutputTokens
421â†’			subagentUsage.APICallCount += agentUsage.APICallCount
422â†’		}
423â†’		if subagentUsage.APICallCount > 0 {
424â†’			mainUsage.SubagentTokens = subagentUsage
425â†’		}
426â†’	}
427â†’
428â†’	return mainUsage, nil
