	if len(commit.ShortSHA) != 7 {
		t.Errorf("expected 7-char short SHA, got %d chars: %q", len(commit.ShortSHA), commit.ShortSHA)
	}
	if len(commit.SHA) != 40 {
		t.Errorf("expected 40-char full SHA, got %d chars", len(commit.SHA))
