 35â†’// Each pair contains the user's prompt, assistant's text response, and files modified.
 36â†’func ExtractAllPromptResponses(transcript []transcriptLine) []PromptResponsePair {
 37â†’	var pairs []PromptResponsePair
 38â†’
 39â†’	// Find all user prompts (messages with string content, not tool results)
 40â†’	var userIndices []int
 41â†’	for i, line := range transcript {
 42â†’		if line.Type == transcriptTypeUser {
 43â†’			var msg userMessage
 44â†’			if err := json.Unmarshal(line.Message, &msg); err != nil {
 45â†’				continue
 46â†’			}
 47â†’			// Only count messages with string content (real user prompts)
 48â†’			if _, ok := msg.Content.(string); ok {
 49â†’				userIndices = append(userIndices, i)
 50â†’			} else if arr, ok := msg.Content.([]interface{}); ok {
 51â†’				// Check if array has text blocks (also a real user prompt)
 52â†’				for _, item := range arr {
 53â†’					if m, ok := item.(map[string]interface{}); ok {
 54â†’						if m["type"] == contentTypeText {
 55â†’							userIndices = append(userIndices, i)
