 57â†’						}
 58â†’					}
 59â†’				}
 60â†’			}
 61â†’		}
 62â†’	}
 63â†’
 64â†’	// For each user prompt, extract the prompt text, following assistant response, and files
 65â†’	for idx, userIdx := range userIndices {
 66â†’		// Determine the range for this prompt's conversation
 67â†’		endIdx := len(transcript)
 68â†’		if idx < len(userIndices)-1 {
 69â†’			endIdx = userIndices[idx+1]
