416â†’	}
417â†’
418â†’	file, err := os.Open(path) //nolint:gosec // Reading from controlled transcript path
419â†’	if err != nil {
420â†’		if os.IsNotExist(err) {
421â†’			return TranscriptPosition{}, nil
422â†’		}
423â†’		return TranscriptPosition{}, fmt.Errorf("failed to open transcript: %w", err)
424â†’	}
425â†’	defer func() { _ = file.Close() }()
426â†’
427â†’	var pos TranscriptPosition
428â†’	reader := bufio.NewReader(file)
429â†’
430â†’	for {
431â†’		lineBytes, err := reader.ReadBytes('\n')
432â†’		if err != nil && err != io.EOF {
433â†’			return TranscriptPosition{}, fmt.Errorf("failed to read transcript: %w", err)
434â†’		}
435â†’
436â†’		if len(lineBytes) == 0 {
437â†’			if err == io.EOF {
438â†’				break
439â†’			}
440â†’			continue
441â†’		}
442â†’
443â†’		pos.LineCount++
444â†’
445â†’		// Parse line to extract UUID (only from user/assistant messages, not summaries)
446â†’		var line transcriptLine
447â†’		if err := json.Unmarshal(lineBytes, &line); err == nil {
448â†’			if line.UUID != "" {
449â†’				pos.LastUUID = line.UUID
450â†’			}
451â†’		}
452â†’
453â†’		if err == io.EOF {
454â†’			break
455â†’		}
456â†’	}
457â†’
458â†’	return pos, nil
459â†’}
460â†’

