 14â†’// TranscriptLine is an alias to the shared transcript.Line type.
 15â†’type TranscriptLine = transcript.Line
 16â†’
 17â†’// Type aliases for internal use.
 18â†’type (
 19â†’	userMessage      = transcript.UserMessage
 20â†’	assistantMessage = transcript.AssistantMessage
 21â†’	toolInput        = transcript.ToolInput
 22â†’)
 23â†’
 24â†’// SerializeTranscript converts transcript lines back to JSONL bytes
 25â†’func SerializeTranscript(lines []TranscriptLine) ([]byte, error) {
 26â†’	var buf bytes.Buffer
 27â†’	for _, line := range lines {
 28â†’		data, err := json.Marshal(line)
 29â†’		if err != nil {
 30â†’			return nil, fmt.Errorf("failed to marshal line: %w", err)
 31â†’		}
 32â†’		buf.Write(data)
 33â†’		buf.WriteByte('\n')
 34â†’	}
 35â†’	return buf.Bytes(), nil
 36â†’}
