 38â†’// ExtractModifiedFiles extracts files modified by tool calls from transcript
 39â†’func ExtractModifiedFiles(lines []TranscriptLine) []string {
 40â†’	fileSet := make(map[string]bool)
 41â†’	var files []string
 42â†’
 43â†’	for _, line := range lines {
 44â†’		if line.Type != "assistant" {
 45â†’			continue
 46â†’		}
 47â†’
 48â†’		var msg assistantMessage
 49â†’		if err := json.Unmarshal(line.Message, &msg); err != nil {
 50â†’			continue
 51â†’		}
 52â†’
 53â†’		for _, block := range msg.Content {
 54â†’			if block.Type != "tool_use" {
 55â†’				continue
 56â†’			}
 57â†’
 58â†’			// Check if it's a file modification tool
 59â†’			isModifyTool := false
 60â†’			for _, name := range FileModificationTools {
 61â†’				if block.Name == name {
 62â†’					isModifyTool = true
 63â†’					break
 64â†’				}
 65â†’			}
 66â†’
 67â†’			if !isModifyTool {
 68â†’				continue
 69â†’			}
 70â†’
 71â†’			var input toolInput
 72â†’			if err := json.Unmarshal(block.Input, &input); err != nil {
 73â†’				continue
 74â†’			}
 75â†’
 76â†’			file := input.FilePath
 77â†’			if file == "" {
 78â†’				file = input.NotebookPath
 79â†’			}
 80â†’
 81â†’			if file != "" && !fileSet[file] {
 82â†’				fileSet[file] = true
 83â†’				files = append(files, file)
 84â†’			}
 85â†’		}
 86â†’	}
 87â†’
 88â†’	return files
 89â†’}
