 91â†’// ExtractLastUserPrompt extracts the last user message from transcript
 92â†’func ExtractLastUserPrompt(lines []TranscriptLine) string {
 93â†’	for i := len(lines) - 1; i >= 0; i-- {
 94â†’		if lines[i].Type != "user" { //nolint:goconst // already present in codebase
 95â†’			continue
 96â†’		}
 97â†’
 98â†’		var msg userMessage
 99â†’		if err := json.Unmarshal(lines[i].Message, &msg); err != nil {
100â†’			continue
101â†’		}
102â†’
103â†’		// Handle string content
104â†’		if str, ok := msg.Content.(string); ok {
105â†’			return str
106â†’		}
107â†’
108â†’		// Handle array content (text blocks)
109â†’		if arr, ok := msg.Content.([]interface{}); ok {
110â†’			var texts []string
111â†’			for _, item := range arr {
112â†’				if m, ok := item.(map[string]interface{}); ok {
113â†’					if m["type"] == "text" {
114â†’						if text, ok := m["text"].(string); ok {
115â†’							texts = append(texts, text)
116â†’						}
117â†’					}
118â†’				}
119â†’			}
120â†’			if len(texts) > 0 {
121â†’				return strings.Join(texts, "\n\n")
122â†’			}
123â†’		}
124â†’	}
125â†’	return ""
126â†’}
