128â†’// TruncateAtUUID returns transcript lines up to and including the line with given UUID
129â†’func TruncateAtUUID(lines []TranscriptLine, uuid string) []TranscriptLine {
130â†’	if uuid == "" {
131â†’		return lines
132â†’	}
133â†’
134â†’	for i, line := range lines {
135â†’		if line.UUID == uuid {
136â†’			return lines[:i+1]
137â†’		}
138â†’	}
139â†’
140â†’	// UUID not found, return full transcript
141â†’	return lines
142â†’}
