144â†’// toolResultBlock represents a tool_result in a user message
145â†’type toolResultBlock struct {
146â†’	Type      string `json:"type"`
147â†’	ToolUseID string `json:"tool_use_id"`
148â†’}
149â†’
150â†’// userMessageWithToolResults represents a user message that may contain tool results
151â†’type userMessageWithToolResults struct {
