155â†’// FindCheckpointUUID finds the UUID of the message containing the tool_result
156â†’// for the given tool_use_id
157â†’func FindCheckpointUUID(lines []TranscriptLine, toolUseID string) (string, bool) {
158â†’	for _, line := range lines {
159â†’		if line.Type != "user" {
160â†’			continue
161â†’		}
162â†’
163â†’		var msg userMessageWithToolResults
164â†’		if err := json.Unmarshal(line.Message, &msg); err != nil {
165â†’			continue
166â†’		}
167â†’
168â†’		for _, block := range msg.Content {
