177â†’// CalculateTokenUsage calculates token usage from a Claude Code transcript.
178â†’// This is specific to Claude/Anthropic's API format where each assistant message
179â†’// contains a usage object with input_tokens, output_tokens, and cache tokens.
180â†’//
181â†’// Due to streaming, multiple transcript rows may share the same message.id.
182â†’// We deduplicate by taking the row with the highest output_tokens for each message.id.
183â†’func CalculateTokenUsage(transcript []TranscriptLine) *agent.TokenUsage {
184â†’	// Map from message.id to the usage with highest output_tokens
185â†’	usageByMessageID := make(map[string]messageUsage)
186â†’
187â†’	for _, line := range transcript {
188â†’		if line.Type != "assistant" {
189â†’			continue
190â†’		}
191â†’
192â†’		var msg messageWithUsage
193â†’		if err := json.Unmarshal(line.Message, &msg); err != nil {
194â†’			continue
195â†’		}
196â†’
197â†’		if msg.ID == "" {
198â†’			continue
199â†’		}
200â†’
201â†’		// Keep the entry with highest output_tokens (final streaming state)
202â†’		existing, exists := usageByMessageID[msg.ID]
203â†’		if !exists || msg.Usage.OutputTokens > existing.OutputTokens {
204â†’			usageByMessageID[msg.ID] = msg.Usage
205â†’		}
206â†’	}
207â†’
208â†’	// Sum up all unique messages
209â†’	usage := &agent.TokenUsage{
210â†’		APICallCount: len(usageByMessageID),
211â†’	}
212â†’	for _, u := range usageByMessageID {
213â†’		usage.InputTokens += u.InputTokens
214â†’		usage.CacheCreationTokens += u.CacheCreationInputTokens
215â†’		usage.CacheReadTokens += u.CacheReadInputTokens
216â†’		usage.OutputTokens += u.OutputTokens
217â†’	}
218â†’
219â†’	return usage
220â†’}
