222â†’// CalculateTokenUsageFromFile calculates token usage from a Claude Code transcript file.
223â†’// If startLine > 0, only considers lines from startLine onwards.
224â†’func CalculateTokenUsageFromFile(path string, startLine int) (*agent.TokenUsage, error) {
225â†’	if path == "" {
226â†’		return &agent.TokenUsage{}, nil
227â†’	}
228â†’
229â†’	lines, _, err := transcript.ParseFromFileAtLine(path, startLine)
230â†’	if err != nil {
231â†’		return nil, err //nolint:wrapcheck // caller adds context
232â†’	}
233â†’
234â†’	return CalculateTokenUsage(lines), nil
235â†’}
