237â†’// ExtractSpawnedAgentIDs extracts agent IDs from Task tool results in a transcript.
238â†’// When a Task tool completes, the tool_result contains "agentId: <id>" in its content.
239â†’// Returns a map of agentID -> toolUseID for all spawned agents.
240â†’func ExtractSpawnedAgentIDs(transcript []TranscriptLine) map[string]string {
241â†’	agentIDs := make(map[string]string)
242â†’
243â†’	for _, line := range transcript {
244â†’		if line.Type != "user" {
245â†’			continue
246â†’		}
247â†’
248â†’		// Parse as array of content blocks (tool results)
249â†’		var contentBlocks []struct {
250â†’			Type      string          `json:"type"`
251â†’			ToolUseID string          `json:"tool_use_id"`
252â†’			Content   json.RawMessage `json:"content"`
253â†’		}
254â†’
255â†’		var msg struct {
256â†’			Content json.RawMessage `json:"content"`
257â†’		}
258â†’		if err := json.Unmarshal(line.Message, &msg); err != nil {
259â†’			continue
260â†’		}
261â†’
262â†’		if err := json.Unmarshal(msg.Content, &contentBlocks); err != nil {
263â†’			continue
264â†’		}
265â†’
266â†’		for _, block := range contentBlocks {
267â†’			if block.Type != "tool_result" {
268â†’				continue
269â†’			}
270â†’
271â†’			// Content can be a string or array of text blocks
272â†’			var textContent string
273â†’
274â†’			// Try as array of text blocks first
275â†’			var textBlocks []struct {
276â†’				Type string `json:"type"`
277â†’				Text string `json:"text"`
278â†’			}
279â†’			if err := json.Unmarshal(block.Content, &textBlocks); err == nil {
280â†’				var textContentSb361 strings.Builder
281â†’				for _, tb := range textBlocks {
282â†’					if tb.Type == "text" {
283â†’						textContentSb361.WriteString(tb.Text + "\n")
284â†’					}
285â†’				}
286â†’				textContent += textContentSb361.String()
287â†’			} else {
288â†’				// Try as plain string
289â†’				var str string
290â†’				if err := json.Unmarshal(block.Content, &str); err == nil {
291â†’					textContent = str
292â†’				}
293â†’			}
294â†’
295â†’			// Look for agentId in the text
296â†’			if agentID := extractAgentIDFromText(textContent); agentID != "" {
297â†’				agentIDs[agentID] = block.ToolUseID
298â†’			}
299â†’		}
300â†’	}
301â†’
302â†’	return agentIDs
303â†’}
304â†’
305â†’// extractAgentIDFromText extracts an agent ID from text containing "agentId: <id>".
306â†’func extractAgentIDFromText(text string) string {
307â†’	const prefix = "agentId: "
308â†’	idx := strings.Index(text, prefix)
309â†’	if idx == -1 {
310â†’		return ""
311â†’	}
312â†’
313â†’	// Extract the ID (alphanumeric characters after the prefix)
314â†’	start := idx + len(prefix)
315â†’	end := start
316â†’	for end < len(text) && (text[end] >= 'a' && text[end] <= 'z' ||
317â†’		text[end] >= 'A' && text[end] <= 'Z' ||
318â†’		text[end] >= '0' && text[end] <= '9') {
319â†’		end++
320â†’	}
321â†’
322â†’	if end > start {
323â†’		return text[start:end]
324â†’	}
325â†’	return ""
326â†’}
327â†’
328â†’// CalculateTotalTokenUsage calculates token usage for a turn, including subagents.
329â†’// It parses the main transcript from startLine, extracts spawned agent IDs,
330â†’// and calculates their token usage from transcripts in subagentsDir.
331â†’func CalculateTotalTokenUsage(transcriptPath string, startLine int, subagentsDir string) (*agent.TokenUsage, error) {
332â†’	if transcriptPath == "" {
333â†’		return &agent.TokenUsage{}, nil
334â†’	}
335â†’
336â†’	// Parse transcript ONCE
337â†’	parsed, _, err := transcript.ParseFromFileAtLine(transcriptPath, startLine)
338â†’	if err != nil {
339â†’		return nil, fmt.Errorf("failed to parse transcript: %w", err)
340â†’	}
341â†’
342â†’	// Calculate token usage from parsed transcript
343â†’	mainUsage := CalculateTokenUsage(parsed)
344â†’
345â†’	// Extract spawned agent IDs from the same parsed transcript
346â†’	agentIDs := ExtractSpawnedAgentIDs(parsed)
347â†’
348â†’	// Calculate subagent token usage
349â†’	if len(agentIDs) > 0 {
350â†’		subagentUsage := &agent.TokenUsage{}
351â†’		for agentID := range agentIDs {
352â†’			agentPath := filepath.Join(subagentsDir, fmt.Sprintf("agent-%s.jsonl", agentID))
353â†’			agentUsage, err := CalculateTokenUsageFromFile(agentPath, 0)
354â†’			if err != nil {
355â†’				// Agent transcript may not exist yet or may have been cleaned up
356â†’				continue
357â†’			}
358â†’			subagentUsage.InputTokens += agentUsage.InputTokens
359â†’			subagentUsage.CacheCreationTokens += agentUsage.CacheCreationTokens
360â†’			subagentUsage.CacheReadTokens += agentUsage.CacheReadTokens
361â†’			subagentUsage.OutputTokens += agentUsage.OutputTokens
362â†’			subagentUsage.APICallCount += agentUsage.APICallCount
363â†’		}
364â†’		if subagentUsage.APICallCount > 0 {
365â†’			mainUsage.SubagentTokens = subagentUsage
366â†’		}
367â†’	}
368â†’
369â†’	return mainUsage, nil
370â†’}
371â†’
372â†’// ExtractAllModifiedFiles extracts files modified by both the main agent and
373â†’// any subagents spawned via the Task tool. It parses the main transcript from
374â†’// startLine, collects modified files from the main agent, then reads each
375â†’// subagent's transcript from subagentsDir to collect their modified files too.
376â†’// The result is a deduplicated list of all modified file paths.
377â†’func ExtractAllModifiedFiles(transcriptPath string, startLine int, subagentsDir string) ([]string, error) {
378â†’	if transcriptPath == "" {
379â†’		return nil, nil
380â†’	}
381â†’
382â†’	// Parse main transcript once
383â†’	parsed, _, err := transcript.ParseFromFileAtLine(transcriptPath, startLine)
384â†’	if err != nil {
385â†’		return nil, fmt.Errorf("failed to parse transcript: %w", err)
386â†’	}
387â†’
388â†’	// Collect modified files from main agent
389â†’	fileSet := make(map[string]bool)
390â†’	var files []string
391â†’	for _, f := range ExtractModifiedFiles(parsed) {
392â†’		if !fileSet[f] {
393â†’			fileSet[f] = true
394â†’			files = append(files, f)
395â†’		}
396â†’	}
397â†’
398â†’	// Find spawned subagents and collect their modified files
399â†’	agentIDs := ExtractSpawnedAgentIDs(parsed)
400â†’	for agentID := range agentIDs {
401â†’		agentPath := filepath.Join(subagentsDir, fmt.Sprintf("agent-%s.jsonl", agentID))
402â†’		agentLines, _, agentErr := transcript.ParseFromFileAtLine(agentPath, 0)
403â†’		if agentErr != nil {
404â†’			// Subagent transcript may not exist yet or may have been cleaned up
405â†’			continue
406â†’		}
407â†’		for _, f := range ExtractModifiedFiles(agentLines) {
408â†’			if !fileSet[f] {
409â†’				fileSet[f] = true
410â†’				files = append(files, f)
411â†’			}
412â†’		}
413â†’	}
414â†’
415â†’	return files, nil
416â†’}
