 50â†’// DetectPresence checks if Claude Code is configured in the repository.
 51â†’func (c *ClaudeCodeAgent) DetectPresence() (bool, error) {
 52â†’	// Get repo root to check for .claude directory
 53â†’	// This is needed because the CLI may be run from a subdirectory
 54â†’	repoRoot, err := paths.RepoRoot()
 55â†’	if err != nil {
 56â†’		// Not in a git repo, fall back to CWD-relative check
 57â†’		repoRoot = "."
 58â†’	}
 59â†’
 60â†’	// Check for .claude directory
 61â†’	claudeDir := filepath.Join(repoRoot, ".claude")
 62â†’	if _, err := os.Stat(claudeDir); err == nil {
 63â†’		return true, nil
 64â†’	}
 65â†’	// Check for .claude/settings.json
 66â†’	settingsFile := filepath.Join(repoRoot, ".claude", "settings.json")
 67â†’	if _, err := os.Stat(settingsFile); err == nil {
 68â†’		return true, nil
 69â†’	}
