 83â†’// ParseHookInput parses Claude Code hook input from stdin.
 84â†’func (c *ClaudeCodeAgent) ParseHookInput(hookType agent.HookType, reader io.Reader) (*agent.HookInput, error) {
 85â†’	data, err := io.ReadAll(reader)
 86â†’	if err != nil {
 87â†’		return nil, fmt.Errorf("failed to read input: %w", err)
 88â†’	}
 89â†’
 90â†’	if len(data) == 0 {
 91â†’		return nil, errors.New("empty input")
 92â†’	}
 93â†’
 94â†’	input := &agent.HookInput{
 95â†’		HookType:  hookType,
 96â†’		Timestamp: time.Now(),
 97â†’		RawData:   make(map[string]interface{}),
 98â†’	}
 99â†’
100â†’	// Parse based on hook type
101â†’	switch hookType {
102â†’	case agent.HookUserPromptSubmit:
103â†’		var raw userPromptSubmitRaw
104â†’		if err := json.Unmarshal(data, &raw); err != nil {
105â†’			return nil, fmt.Errorf("failed to parse user prompt submit: %w", err)
106â†’		}
107â†’		input.SessionID = raw.SessionID
108â†’		input.SessionRef = raw.TranscriptPath
109â†’		input.UserPrompt = raw.Prompt
110â†’
111â†’	case agent.HookSessionStart, agent.HookSessionEnd, agent.HookStop:
112â†’		var raw sessionInfoRaw
113â†’		if err := json.Unmarshal(data, &raw); err != nil {
114â†’			return nil, fmt.Errorf("failed to parse session info: %w", err)
115â†’		}
116â†’		input.SessionID = raw.SessionID
117â†’		input.SessionRef = raw.TranscriptPath
118â†’
119â†’	case agent.HookPreToolUse:
120â†’		var raw taskHookInputRaw
121â†’		if err := json.Unmarshal(data, &raw); err != nil {
122â†’			return nil, fmt.Errorf("failed to parse pre-tool input: %w", err)
123â†’		}
