340â†’// TranscriptAnalyzer interface implementation
341â†’
342â†’// GetTranscriptPosition returns the current line count of a Claude Code transcript.
343â†’// Claude Code uses JSONL format, so position is the number of lines.
344â†’// This is a lightweight operation that only counts lines without parsing JSON.
345â†’// Uses bufio.Reader to handle arbitrarily long lines (no size limit).
346â†’// Returns 0 if the file doesn't exist or is empty.
347â†’func (c *ClaudeCodeAgent) GetTranscriptPosition(path string) (int, error) {
348â†’	if path == "" {
349â†’		return 0, nil
350â†’	}
351â†’
352â†’	file, err := os.Open(path) //nolint:gosec // Path comes from Claude Code transcript location
353â†’	if err != nil {
354â†’		if os.IsNotExist(err) {
355â†’			return 0, nil
356â†’		}
357â†’		return 0, fmt.Errorf("failed to open transcript file: %w", err)
358â†’	}
359â†’	defer file.Close()
360â†’
361â†’	reader := bufio.NewReader(file)
362â†’	lineCount := 0
363â†’
364â†’	for {
365â†’		_, err := reader.ReadBytes('\n')
366â†’		if err != nil {
367â†’			if err == io.EOF {
368â†’				break
369â†’			}
370â†’			return 0, fmt.Errorf("failed to read transcript: %w", err)
371â†’		}
372â†’		lineCount++
373â†’	}
374â†’
375â†’	return lineCount, nil
376â†’}
377â†’
378â†’// ExtractModifiedFilesFromOffset extracts files modified since a given line number.
379â†’// For Claude Code (JSONL format), offset is the starting line number.
380â†’// Uses bufio.Reader to handle arbitrarily long lines (no size limit).
381â†’// Returns:
382â†’//   - files: list of file paths modified by Claude (from Write/Edit tools)
383â†’//   - currentPosition: total number of lines in the file
384â†’//   - error: any error encountered during reading
385â†’func (c *ClaudeCodeAgent) ExtractModifiedFilesFromOffset(path string, startOffset int) (files []string, currentPosition int, err error) {
386â†’	if path == "" {
387â†’		return nil, 0, nil
388â†’	}
389â†’
390â†’	file, openErr := os.Open(path) //nolint:gosec // Path comes from Claude Code transcript location
391â†’	if openErr != nil {
392â†’		return nil, 0, fmt.Errorf("failed to open transcript file: %w", openErr)
393â†’	}
394â†’	defer file.Close()
395â†’
396â†’	reader := bufio.NewReader(file)
397â†’	var lines []TranscriptLine
398â†’	lineNum := 0
399â†’
400â†’	for {
401â†’		lineData, readErr := reader.ReadBytes('\n')
402â†’		if readErr != nil && readErr != io.EOF {
403â†’			return nil, 0, fmt.Errorf("failed to read transcript: %w", readErr)
404â†’		}
405â†’
406â†’		if len(lineData) > 0 {
407â†’			lineNum++
408â†’			if lineNum > startOffset {
409â†’				var line TranscriptLine
410â†’				if parseErr := json.Unmarshal(lineData, &line); parseErr == nil {
411â†’					lines = append(lines, line)
412â†’				}
413â†’				// Skip malformed lines silently
414â†’			}
415â†’		}
416â†’
417â†’		if readErr == io.EOF {
418â†’			break
419â†’		}
420â†’	}
421â†’
422â†’	return ExtractModifiedFiles(lines), lineNum, nil
423â†’}
