 59â†’func runDebugAutoCommit(w io.Writer, transcriptPath string) error {
 60â†’	// Check if we're in a git repository
 61â†’	repoRoot, err := paths.RepoRoot()
 62â†’	if err != nil {
 63â†’		fmt.Fprintln(w, "Not in a git repository")
 64â†’		return nil //nolint:nilerr // not being in a git repo is expected, not an error for status check
 65â†’	}
 66â†’	fmt.Fprintf(w, "Repository: %s\n\n", repoRoot)
 67â†’
 68â†’	// Print strategy info
 69â†’	strat := GetStrategy()
 70â†’	isAutoCommit := strat.Name() == strategy.StrategyNameAutoCommit
 71â†’	printStrategyInfo(w, strat, isAutoCommit)
 72â†’
 73â†’	// Print session state
 74â†’	currentSession := printSessionState(w)
 75â†’
 76â†’	// Auto-detect transcript if not provided
 77â†’	if transcriptPath == "" && currentSession != "" {
 78â†’		detected, detectErr := findTranscriptForSession(currentSession)
 79â†’		if detectErr != nil {
 80â†’			fmt.Fprintf(w, "\nCould not auto-detect transcript: %v\n", detectErr)
 81â†’		} else if detected != "" {
