 83â†’			fmt.Fprintf(w, "\nAuto-detected transcript: %s\n", transcriptPath)
 84â†’		}
 85â†’	}
 86â†’
 87â†’	// Print file changes and get total
 88â†’	fmt.Fprintln(w, "\n=== File Changes ===")
 89â†’	var totalChanges int
 90â†’	if transcriptPath != "" {
 91â†’		totalChanges = printTranscriptChanges(w, transcriptPath, currentSession, repoRoot)
 92â†’	} else {
 93â†’		var err error
