167â†’func printTranscriptChanges(w io.Writer, transcriptPath, currentSession, repoRoot string) int {
168â†’	fmt.Fprintf(w, "\nParsing transcript: %s\n", transcriptPath)
169â†’
170â†’	var modifiedFromTranscript, newFiles, deletedFiles []string
171â†’
172â†’	// Parse transcript
173â†’	parsed, _, parseErr := transcript.ParseFromFileAtLine(transcriptPath, 0)
174â†’	if parseErr != nil {
175â†’		fmt.Fprintf(w, "  Error parsing transcript: %v\n", parseErr)
176â†’	} else {
177â†’		modifiedFromTranscript = extractModifiedFiles(parsed)
178â†’		fmt.Fprintf(w, "  Found %d modified files in transcript\n", len(modifiedFromTranscript))
179â†’	}
180â†’	// Compute new and deleted files (single git status call)
181â†’	// Load preState only if we have an active session (needed for new file detection)
182â†’	var preState *PrePromptState
183â†’	if currentSession != "" {
184â†’		var loadErr error
185â†’		preState, loadErr = LoadPrePromptState(currentSession)
186â†’		if loadErr != nil {
187â†’			fmt.Fprintf(w, "  Error loading pre-prompt state: %v\n", loadErr)
188â†’		}
189â†’	}
190â†’	// Always call DetectFileChanges - deleted files don't depend on preState
191â†’	fileChanges, err := DetectFileChanges(preState.PreUntrackedFiles())
192â†’	if err != nil {
193â†’		fmt.Fprintf(w, "  Error computing file changes: %v\n", err)
194â†’	}
195â†’	if fileChanges != nil {
196â†’		newFiles = fileChanges.New
197â†’		deletedFiles = fileChanges.Deleted
198â†’	}
199â†’
200â†’	// Filter and normalize paths
201â†’	modifiedFromTranscript = FilterAndNormalizePaths(modifiedFromTranscript, repoRoot)
202â†’	newFiles = FilterAndNormalizePaths(newFiles, repoRoot)
203â†’	deletedFiles = FilterAndNormalizePaths(deletedFiles, repoRoot)
204â†’
205â†’	// Print files
206â†’	printFileList(w, "Modified (from transcript)", "M", modifiedFromTranscript)
207â†’	printFileList(w, "New files (created during session)", "+", newFiles)
208â†’	printFileList(w, "Deleted files", "D", deletedFiles)
209â†’
210â†’	totalChanges := len(modifiedFromTranscript) + len(newFiles) + len(deletedFiles)
211â†’	if totalChanges == 0 {
212â†’		fmt.Fprintln(w, "\nNo changes detected from transcript")
213â†’	}
214â†’
215â†’	return totalChanges
