282â†’// getFileChanges returns the current file changes from git status.
283â†’// Returns (modifiedFiles, untrackedFiles, deletedFiles, stagedFiles, error)
284â†’func getFileChanges() ([]string, []string, []string, []string, error) {
285â†’	repo, err := openRepository()
286â†’	if err != nil {
287â†’		return nil, nil, nil, nil, err
288â†’	}
289â†’
290â†’	worktree, err := repo.Worktree()
291â†’	if err != nil {
292â†’		return nil, nil, nil, nil, fmt.Errorf("getting worktree: %w", err)
293â†’	}
294â†’
295â†’	status, err := worktree.Status()
296â†’	if err != nil {
297â†’		return nil, nil, nil, nil, fmt.Errorf("getting status: %w", err)
298â†’	}
299â†’
300â†’	var modifiedFiles, untrackedFiles, deletedFiles, stagedFiles []string
301â†’
302â†’	for file, st := range status {
303â†’		// Skip .entire directory
304â†’		if paths.IsInfrastructurePath(file) {
305â†’			continue
306â†’		}
307â†’
308â†’		// Check staging area first
309â†’		switch st.Staging {
310â†’		case git.Added, git.Modified:
311â†’			stagedFiles = append(stagedFiles, file)
312â†’			continue
313â†’		case git.Deleted:
314â†’			deletedFiles = append(deletedFiles, file)
315â†’			continue
316â†’		case git.Unmodified, git.Renamed, git.Copied, git.UpdatedButUnmerged, git.Untracked:
317â†’			// Fall through to check worktree status
318â†’		}
319â†’
320â†’		// Check worktree status
321â†’		switch st.Worktree {
322â†’		case git.Modified:
323â†’			modifiedFiles = append(modifiedFiles, file)
324â†’		case git.Untracked:
325â†’			untrackedFiles = append(untrackedFiles, file)
326â†’		case git.Deleted:
327â†’			deletedFiles = append(deletedFiles, file)
328â†’		case git.Unmodified, git.Added, git.Renamed, git.Copied, git.UpdatedButUnmerged:
329â†’			// No action needed
330â†’		}
331â†’	}
332â†’
333â†’	// Sort for consistent output
334â†’	sort.Strings(modifiedFiles)
335â†’	sort.Strings(untrackedFiles)
336â†’	sort.Strings(deletedFiles)
337â†’	sort.Strings(stagedFiles)
338â†’
339â†’	return modifiedFiles, untrackedFiles, deletedFiles, stagedFiles, nil
340â†’}
