 15â†’// ParseFromBytes parses transcript content from a byte slice.
 16â†’// Uses bufio.Reader to handle arbitrarily long lines.
 17â†’func ParseFromBytes(content []byte) ([]Line, error) {
 18â†’	var lines []Line
 19â†’	reader := bufio.NewReader(bytes.NewReader(content))
 20â†’
 21â†’	for {
 22â†’		lineBytes, err := reader.ReadBytes('\n')
 23â†’		if err != nil && err != io.EOF {
 24â†’			return nil, fmt.Errorf("failed to read transcript: %w", err)
 25â†’		}
 26â†’
 27â†’		// Handle empty line or EOF without content
 28â†’		if len(lineBytes) == 0 {
 29â†’			if err == io.EOF {
 30â†’				break
 31â†’			}
 32â†’			continue
 33â†’		}
 34â†’
 35â†’		var line Line
 36â†’		if err := json.Unmarshal(lineBytes, &line); err == nil {
 37â†’			lines = append(lines, line)
 38â†’		}
 39â†’
 40â†’		if err == io.EOF {
 41â†’			break
 42â†’		}
 43â†’	}
 44â†’
 45â†’	return lines, nil
 46â†’}
