 48â†’// ParseFromFileAtLine reads and parses a transcript file starting from a specific line.
 49â†’// Uses bufio.Reader to handle arbitrarily long lines (no size limit).
 50â†’// Returns:
 51â†’//   - lines: parsed transcript lines from startLine onwards (malformed lines skipped)
 52â†’//   - totalLines: total number of lines in the file (including malformed ones)
 53â†’//   - error: any error encountered during reading
 54â†’//
 55â†’// The startLine parameter is 0-indexed (startLine=0 reads from the beginning).
 56â†’// This is useful for incremental parsing when you've already processed some lines.
 57â†’func ParseFromFileAtLine(path string, startLine int) ([]Line, int, error) {
 58â†’	file, err := os.Open(path) //nolint:gosec // path is a controlled transcript file path
 59â†’	if err != nil {
 60â†’		return nil, 0, fmt.Errorf("failed to open transcript: %w", err)
 61â†’	}
 62â†’	defer func() { _ = file.Close() }()
 63â†’
 64â†’	var lines []Line
 65â†’	reader := bufio.NewReader(file)
 66â†’
 67â†’	totalLines := 0
 68â†’	for {
 69â†’		lineBytes, err := reader.ReadBytes('\n')
 70â†’		if err != nil && err != io.EOF {
 71â†’			return nil, 0, fmt.Errorf("failed to read transcript: %w", err)
 72â†’		}
 73â†’
 74â†’		// Handle empty line or EOF without content
 75â†’		if len(lineBytes) == 0 {
 76â†’			if err == io.EOF {
 77â†’				break
 78â†’			}
 79â†’			continue
 80â†’		}
 81â†’
 82â†’		// Count all lines for totalLines, but only parse after startLine
 83â†’		if totalLines >= startLine {
 84â†’			var line Line
 85â†’			if err := json.Unmarshal(lineBytes, &line); err == nil {
 86â†’				lines = append(lines, line)
 87â†’			}
 88â†’		}
 89â†’		totalLines++
 90â†’
 91â†’		if err == io.EOF {
 92â†’			break
 93â†’		}
 94â†’	}
 95â†’
 96â†’	return lines, totalLines, nil
 97â†’}
 98â†’
 99â†’// SliceFromLine returns the content starting from line number `startLine` (0-indexed).
100â†’// This is used to extract only the checkpoint-specific portion of a cumulative transcript.
101â†’// For example, if startLine is 2, lines 0 and 1 are skipped and the result starts at line 2.
102â†’// Returns empty slice if startLine exceeds the number of lines.
103â†’func SliceFromLine(content []byte, startLine int) []byte {
104â†’	if len(content) == 0 || startLine <= 0 {
105â†’		return content
106â†’	}
107â†’
108â†’	// Find the byte offset where startLine begins
109â†’	lineCount := 0
110â†’	offset := 0
111â†’	for i, b := range content {
112â†’		if b == '\n' {
113â†’			lineCount++
114â†’			if lineCount == startLine {
115â†’				offset = i + 1
116â†’				break
117â†’			}
118â†’		}
119â†’	}
120â†’
121â†’	// If we didn't find enough lines, return empty
122â†’	if lineCount < startLine {
123â†’		return nil
124â†’	}
125â†’
126â†’	// If offset is beyond content, return empty
127â†’	if offset >= len(content) {
128â†’		return nil
129â†’	}
130â†’
131â†’	return content[offset:]
132â†’}
