135â†’// Handles both string and array content formats.
136â†’// IDE-injected context tags (like <ide_opened_file>) are stripped from the result.
137â†’// Returns empty string if the message cannot be parsed or contains no text.
138â†’func ExtractUserContent(message json.RawMessage) string {
